        self.id2word = {}
        self.word2id = {}

    def add_word(self, word):
        if word not in self.word2id:
            new_id = len(self.word2id)
            self.id2word[new_id] = word
            self.word2id[word] = new_id

    def get_word(self, id):
        return self.id2word.get(id)

    def get_id(self, word):
