To achieve one index cache per index file, you can use a dictionary to store the index caches. Here's an example in Python:

```python
import os
import pickle

class IndexCache:
    def __init__(self):
        self.caches = {}

    def get_cache(self, index_file):
        if index_file not in self.caches:
            self.caches[index_file] = {}
        return self.caches[index_file]

    def put(self, index_file, key, value):
        cache = self.get_cache(index_file)
        cache[key] = value

    def get(self, index_file, key):
        cache = self.get_cache(index_file)
        return cache.get(key)

    def delete(self, index_file, key):
        cache = self.get_cache(index_file)
        if key in cache:
            del cache[key]

    def save(self, index_file):
        cache = self.get_cache(index_file)
        with open(f"{index_file}.cache", "wb") as f:
            pickle.dump(cache, f)

    def load(self, index_file):
        try:
            with open(f"{index_file}.cache", "rb") as f:
                cache = pickle.load(f)
                self.caches[index_file] = cache

