Here's the refactored code that combines the context and helper function into a custom hook:

**Notification Hook**
```typescript
// src/hooks/useNotification.ts
import { createContext, useContext, useState } from 'react';
import { HTMLHuelNotificationElement } from '../helpers/notification.helpers';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

interface UseNotificationContext {
  notificationElement: HTMLHuelNotificationElement | null;
  notify: (props: NotificationProps) => Promise<void>;
}

const NotificationContext = createContext<UseNotificationContext>({
  notificationElement: null,
  notify: () => Promise.resolve(),
});

const useNotification = (): UseNotificationContext => {
  const notificationElement = useContext(NotificationContext);
  const [notificationElementState, setNotificationElementState] =
    useState<HTMLHuelNotificationElement | null>(notificationElement);

  const notify = async (props: NotificationProps) => {
    if (!notificationElementState) return;

    const { heading, subheading, type } = props;
    await notificationElementState.open({
      heading,
      subheading,
      type,
    });
  };

  return { notificationElement: notificationElementState, notify };
};

export default useNotification;
``

